class p extends a{checkSaveNameRepeat(){
    for(const e of this.saves){
        const t=new Set;for(const r of e.saves){
            if(t.has(r.name)) throw new Error(`Warning: Save file name should not be repeated for: "${r.name}"`);t.add(r.name)
        }
    }
}
getSaveCount(){
    return this.saves.map((e=>e.getSaveCount())).reduce(((e,t)=>e+t),0)
}
hasSaves(){
    return this.getSaveCount()>0
}
getSortedSaves(e=0){
    return!this.hasSaves||e>this.getMaxSortMode()?[]:p.sortingMethods[e].method(this.saves)
}
static sortingMethods=[{name:"Early to late",method:e=>[...e]},{name:"Late to early",method:e=>[...e].reverse()}]}
